#!/bin/bash
# Benchmark Comparison Script
#
# Compares two k6 benchmark result files (--summary-export format) and shows
# side-by-side metrics with delta percentages. Highlights regressions (>10%).
#
# Usage: ./scripts/compare_benchmarks.sh <baseline.json> <current.json>
#
# The JSON files should be k6 --summary-export output, as generated by
# run-benchmarks.sh (auto-saved to test-results/ directory).

set -e

# Colors
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
BLUE='\033[0;34m'
NC='\033[0m'

# Help function
show_help() {
    echo -e "${BLUE}Higth — Benchmark Comparison Script${NC}"
    echo ""
    echo "Compares two k6 benchmark results (--summary-export format) side-by-side."
    echo "Shows p50/p95/p99 latency, request count, and error rate with delta %."
    echo ""
    echo -e "${BLUE}Usage:${NC}"
    echo "  ./scripts/compare_benchmarks.sh <baseline.json> <current.json>"
    echo "  ./scripts/compare_benchmarks.sh --help"
    echo ""
    echo -e "${BLUE}Arguments:${NC}"
    echo "  baseline.json   First result file (the 'before' state)"
    echo "  current.json    Second result file (the 'after' state)"
    echo ""
    echo -e "${BLUE}Where to find the files:${NC}"
    echo "  run-benchmarks.sh auto-saves results to test-results/ directory."
    echo "  Files are named: <scenario>_<tier>_<timestamp>.json"
    echo ""
    echo -e "${BLUE}Typical workflow:${NC}"
    echo "  1. Run benchmark:    ./tests/run-benchmarks.sh --tier low -s hot"
    echo "  2. Change something: (hardware, config, code)"
    echo "  3. Run again:        ./tests/run-benchmarks.sh --tier low -s hot"
    echo "  4. Compare:          ./scripts/compare_benchmarks.sh <old>.json <new>.json"
    echo ""
    echo -e "${BLUE}Output legend:${NC}"
    echo -e "  ${GREEN}Green${NC}  = improvement (latency decreased or throughput increased)"
    echo -e "  ${YELLOW}Yellow${NC} = minor change (<10%)"
    echo -e "  ${RED}Red${NC}    = regression (>10% — latency increased or throughput dropped)"
    echo ""
    echo -e "${BLUE}Dependencies:${NC}"
    echo "  jq — required for JSON parsing. Install: sudo apt install jq"
    echo ""
    echo -e "${BLUE}Examples:${NC}"
    echo "  # Compare two specific runs"
    echo "  ./scripts/compare_benchmarks.sh test-results/hot_low_20260419_120000.json \\"
    echo "                                     test-results/hot_low_20260421_140000.json"
    echo ""
    echo "  # Compare with wildcard (picks most recent two)"
    echo "  ./scripts/compare_benchmarks.sh \$(ls -t test-results/hot_low_*.json | tail -1) \\"
    echo "                                     \$(ls -t test-results/hot_low_*.json | head -1)"
}

# Parse --help before requiring file arguments
for arg in "$@"; do
    case $arg in
        --help|-h)
            show_help
            exit 0
            ;;
    esac
done

# Check arguments
if [ $# -lt 2 ]; then
    echo -e "${BLUE}Usage:${NC} ./scripts/compare_benchmarks.sh <baseline.json> <current.json>"
    echo "Run with --help for full documentation."
    exit 1
fi

BASELINE="$1"
CURRENT="$2"

# Validate files exist
for f in "$BASELINE" "$CURRENT"; do
    if [ ! -f "$f" ]; then
        echo -e "${RED}[ERROR]${NC} File not found: $f"
        exit 1
    fi
done

# Check for jq
if ! command -v jq &>/dev/null; then
    echo -e "${RED}[ERROR]${NC} jq is required. Install with: sudo apt install jq"
    exit 1
fi

echo -e "${BLUE}╔════════════════════════════════════════════════════════════════╗${NC}"
echo -e "${BLUE}║         Benchmark Comparison                                    ║${NC}"
echo -e "${BLUE}╚════════════════════════════════════════════════════════════════╝${NC}"
echo ""
echo -e "  Baseline: ${BASELINE}"
echo -e "  Current:  ${CURRENT}"
echo ""

# Extract a metric value from k6 --summary-export JSON
# Format: .metrics.<metric_name>.<stat_key>  (stats are at top level, not nested under .values)
# k6 stat keys: "avg", "min", "max", "med" (p50), "p(90)", "p(95)", "p(99)"
extract_metric() {
    local file="$1"
    local metric="$2"
    local stat="$3"
    local val
    val=$(jq -r ".metrics[\"$metric\"][\"$stat\"] // \"N/A\"" "$file" 2>/dev/null)
    if [ "$val" = "null" ] || [ -z "$val" ]; then
        echo "N/A"
    else
        echo "$val"
    fi
}

# Extract request count from --summary-export
extract_count() {
    local file="$1"
    local val
    val=$(jq -r ".metrics.http_reqs.count // \"N/A\"" "$file" 2>/dev/null)
    if [ "$val" = "null" ] || [ -z "$val" ]; then
        echo "N/A"
    else
        echo "$val"
    fi
}

# Extract error rate from --summary-export
# k6 naming: "passes" = requests that failed the check (HTTP errors),
#             "fails"  = requests that passed the check (successful).
# Error rate = passes / (passes + fails)
extract_error_rate() {
    local file="$1"
    local error_count
    local success_count
    error_count=$(jq -r ".metrics.http_req_failed.passes // 0" "$file" 2>/dev/null)
    success_count=$(jq -r ".metrics.http_req_failed.fails // 0" "$file" 2>/dev/null)
    local total=$((error_count + success_count))
    if [ "$total" -gt 0 ] 2>/dev/null; then
        echo "scale=2; $error_count / $total * 100" | bc 2>/dev/null || echo "0.00"
    else
        # Fallback: check if http_req_failed has a value field (rate)
        local rate=$(jq -r ".metrics.http_req_failed.value // \"N/A\"" "$file" 2>/dev/null)
        if [ "$rate" != "N/A" ] && [ "$rate" != "null" ]; then
            echo "scale=2; $rate * 100" | bc 2>/dev/null || echo "0.00"
        else
            echo "N/A"
        fi
    fi
}

# Calculate delta percentage
calc_delta() {
    local baseline="$1"
    local current="$2"
    if [ "$baseline" = "N/A" ] || [ "$current" = "N/A" ]; then
        echo "N/A"
        return
    fi
    if [ "$(echo "$baseline == 0" | bc 2>/dev/null)" = "1" ]; then
        echo "N/A"
        return
    fi
    echo "scale=1; ($current - $baseline) / $baseline * 100" | bc 2>/dev/null || echo "0"
}

# Format delta with color
format_delta() {
    local delta="$1"
    local lower_is_better="$2"

    if [ "$delta" = "N/A" ]; then
        echo -e "${YELLOW}N/A${NC}"
        return
    fi

    local is_improvement=false
    if [ "$lower_is_better" = "true" ]; then
        if [ "$(echo "$delta < 0" | bc 2>/dev/null)" = "1" ]; then
            is_improvement=true
        fi
    else
        if [ "$(echo "$delta > 0" | bc 2>/dev/null)" = "1" ]; then
            is_improvement=true
        fi
    fi

    local abs_delta=$(echo "$delta" | tr -d '-')

    if [ "$is_improvement" = "true" ]; then
        echo -e "${GREEN}${delta}%${NC}"
    elif [ "$(echo "$abs_delta > 10" | bc 2>/dev/null)" = "1" ]; then
        echo -e "${RED}${delta}%${NC} ⚠ REGRESSION"
    else
        echo -e "${YELLOW}${delta}%${NC}"
    fi
}

# Map stat names to k6 --summary-export keys
map_stat() {
    case "$1" in
        p50) echo "med" ;;
        p95) echo "p(95)" ;;
        p99) echo "p(99)" ;;
        *) echo "$1" ;;
    esac
}

# ── HTTP Request Duration ──────────────────────────────────────────────
echo -e "${BLUE}HTTP Request Duration (ms)${NC}"
echo -e "${BLUE}─────────────────────────────────────────────────────${NC}"
printf "  %-10s  %-12s  %-12s  %-15s\n" "Metric" "Baseline" "Current" "Delta"
printf "  %-10s  %-12s  %-12s  %-15s\n" "----------" "------------" "------------" "---------------"

for stat_name in p50 p95 p99 avg max; do
    k6_key=$(map_stat "$stat_name")
    baseline=$(extract_metric "$BASELINE" "http_req_duration" "$k6_key")
    current=$(extract_metric "$CURRENT" "http_req_duration" "$k6_key")

    # Convert seconds to ms (k6 reports in seconds), round to 2 decimal places
    if [ "$baseline" != "N/A" ]; then baseline=$(printf "%.2f" "$(echo "$baseline * 1000" | bc -l)"); fi
    if [ "$current" != "N/A" ]; then current=$(printf "%.2f" "$(echo "$current * 1000" | bc -l)"); fi

    delta=$(calc_delta "$baseline" "$current")
    delta_formatted=$(format_delta "$delta" "true")

    printf "  %-10s  %-12s  %-12s  %b\n" "$stat_name" "${baseline}ms" "${current}ms" "$delta_formatted"
done

echo ""
echo -e "${BLUE}Request Statistics${NC}"
echo -e "${BLUE}─────────────────────────────────────────────────────${NC}"

base_count=$(extract_count "$BASELINE")
curr_count=$(extract_count "$CURRENT")
count_delta=$(calc_delta "$base_count" "$curr_count")

printf "  %-15s  %-12s  %-12s  %b\n" "Total Requests" "$base_count" "$curr_count" "$(format_delta "$count_delta" "false")"

base_errors=$(extract_error_rate "$BASELINE")
curr_errors=$(extract_error_rate "$CURRENT")
printf "  %-15s  %-12s  %-12s  %b\n" "Error Rate" "${base_errors}%" "${curr_errors}%" "$(format_delta "$(calc_delta "$base_errors" "$curr_errors")" "true")"

echo ""
echo -e "${BLUE}─────────────────────────────────────────────────────${NC}"
echo -e "  ${GREEN}Green${NC} = improvement  ${YELLOW}Yellow${NC} = minor change  ${RED}Red${NC} = regression (>10%)"
echo ""
